import React, { useState } from 'react';
import { useContent } from '../context/ContentContext';
import { Project } from '../types';
import ProjectModal from './ProjectModal';
import Editable from './Editable';
import { Layers, ArrowRight, Plus, Trash2 } from 'lucide-react';

const Projects: React.FC = () => {
  const { projects, updateProject, addProject, removeProject, isAdmin } = useContent();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const openProject = (project: Project) => {
    // Only open modal if not clicking on an input/textarea in admin mode
    // (This is handled naturally by event propagation usually, but good to be mindful)
    setSelectedProject(project);
    setIsModalOpen(true);
  };

  const handleEdit = (id: string, field: keyof Project, val: any) => {
    updateProject(id, field, val);
    // If this project is currently open in modal, we need to update the local selectedProject too 
    // effectively, but since we pass the object from the array, the modal should receive updates 
    // if we pass the project ID and let the modal fetch it, or if we rely on re-renders.
    // However, selectedProject is state. We should sync it.
    if (selectedProject && selectedProject.id === id) {
       setSelectedProject(prev => prev ? ({ ...prev, [field]: val }) : null);
    }
  };

  return (
    <section id="projects" className="py-24 bg-slate-50 dark:bg-slate-950">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
