           {isAdmin && (
             <button 
               onClick={addProject}
               className="bg-green-600 text-white px-4 py-2 rounded flex items-center"
             >
               <Plus size={16} className="mr-2" /> Add Project
             </button>
           )}
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project) => (
            <div 
              key={project.id} 
              className="group bg-white dark:bg-slate-900 rounded-2xl overflow-hidden shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-300 border border-slate-200 dark:border-slate-800 flex flex-col relative"
            >
              {isAdmin && (
                 <button 
                   onClick={(e) => {
                     e.stopPropagation();
                     removeProject(project.id);
                   }}
                   className="absolute top-2 right-2 z-30 bg-red-500 text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                 >
                   <Trash2 size={16} />
                 </button>
              )}

              {/* Image Container */}
              <div className="relative h-48 overflow-hidden cursor-pointer" onClick={() => openProject(project)}>
                <div className="absolute inset-0 bg-slate-900/20 group-hover:bg-slate-900/0 transition-colors z-10"></div>
                <img 
                  src={project.image} 
                  alt={project.title} 
                  className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700" 
                />
                <div className="absolute top-4 left-4 z-20">
                   <span className="px-3 py-1 text-xs font-bold uppercase tracking-wider text-white bg-slate-900/60 backdrop-blur-md rounded-full">
                    {project.category}
                  </span>
                </div>
              </div>

              {/* Content */}
              <div className="p-6 flex-1 flex flex-col">
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-3 group-hover:text-primary-600 transition-colors">
                  <Editable 
                    value={project.title} 
                    onSave={(val) => handleEdit(project.id, 'title', val)}
                  />
                </h3>
                <div className="text-slate-600 dark:text-slate-400 text-sm leading-relaxed mb-6 line-clamp-3">
                   <Editable 
                    value={project.description} 
                    onSave={(val) => handleEdit(project.id, 'description', val)}
                    textarea
                  />
                </div>

                <div className="mt-auto flex items-center justify-between">
                   <div className="flex -space-x-2 overflow-hidden" onClick={() => openProject(project)}>
                      {project.tags.slice(0,3).map((tag, i) => (
                         <div key={i} className="bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded text-[10px] text-slate-500 font-mono border border-white dark:border-slate-900">
